from test_public import database, sql


def test_shared_leaf_quantity_remains_correct_with_a_legacy_cycle():
    db = database([
        ("kit", "module", 2),
        ("kit", "bolt", 1),
        ("module", "bolt", 3),
        ("module", "kit", 1),
    ])
    exploded = db.execute(sql("explode_work_order.sql"), {"root_sku": "kit"}).fetchall()
    assert exploded == [("bolt", 1, 1), ("module", 2, 1), ("bolt", 6, 2)]
    assert db.execute(
        sql("required_materials.sql"), {"root_sku": "kit", "build_count": 4}
    ).fetchall() == [("bolt", 28)]
